import Foundation

struct CategoryContent14 {
    static let aiPractice = CategoryData(
        id: "ai_practice", name: "AI in Practice", icon: "hand.raised.fingers.spread", colorName: "aiPrimary",
        description: "Put your AI skills to work with real-world challenges",
        lessons: [lesson1, lesson2, lesson3, lesson4, lesson5, lesson6], order: 13,
        unlockRequirement: .completeCategoryMinimum("ai_basics")
    )

    static let lesson1 = LessonData(id: "aip_l1", title: "Evaluating AI Output", description: "Is this AI response good or bad?", categoryId: "ai_practice", questions: [
        Question(id: "aip1_q1", type: .multipleChoice, questionText: "What is the FIRST thing you should do when you receive a response from an AI like Claude or GPT?", options: ["Check if the information seems accurate and relevant", "Copy and paste it directly into your work", "Share it on social media immediately", "Assume it is completely correct"], correctAnswer: "Check if the information seems accurate and relevant", explanation: "AI responses can contain errors or hallucinations. Always evaluate the output before using it, no matter which model generated it."),
        Question(id: "aip1_q2", type: .trueFalse, questionText: "A longer AI response is always better than a shorter one.", options: ["True", "False"], correctAnswer: "False", explanation: "Length does not equal quality. A concise, accurate response is often better than a long, rambling one. Good AI output is relevant, accurate, and appropriately detailed."),
        Question(id: "aip1_q3", type: .scenarioJudgment, questionText: "An AI writes a paragraph about the history of the internet and claims it was invented in 1995. Should you trust this?", options: ["No, verify the date independently", "Yes, AI knows history well", "It depends on the model"], correctAnswer: "No, verify the date independently", explanation: "The internet's origins trace back to ARPANET in 1969, not 1995. AI models can confidently state incorrect dates and facts, so always verify specific claims."),
        Question(id: "aip1_q4", type: .fillInBlank, questionText: "When an AI confidently presents false information as fact, this is called a __________.", options: ["hallucination", "compilation", "calibration", "optimization"], correctAnswer: "hallucination", explanation: "AI hallucination occurs when a model generates plausible-sounding but factually incorrect information. This is a known limitation of all current language models."),
        Question(id: "aip1_q5", type: .matchPairs, questionText: "Match each quality indicator to what it checks in AI output:", matchPairs: [
            MatchPair(term: "Accuracy", definition: "Are the facts correct?"),
            MatchPair(term: "Relevance", definition: "Does it answer the question?"),
            MatchPair(term: "Completeness", definition: "Is anything important missing?"),
            MatchPair(term: "Clarity", definition: "Is it easy to understand?")
        ], explanation: "Evaluating AI output across multiple dimensions helps you determine whether a response is truly useful or needs improvement."),
        Question(id: "aip1_q6", type: .multipleChoice, questionText: "Which AI output quality issue is HARDEST for most people to detect?", options: ["Subtle factual errors mixed with correct information", "Completely off-topic responses", "Responses in the wrong language", "Responses that are obviously too short"], correctAnswer: "Subtle factual errors mixed with correct information", explanation: "AI models are especially tricky when they weave small errors into mostly accurate text. This makes fact-checking individual claims essential.")
    ], order: 0, difficulty: .beginner)

    static let lesson2 = LessonData(id: "aip_l2", title: "Choosing the Right AI Tool", description: "Pick the best AI for the job", categoryId: "ai_practice", questions: [
        Question(id: "aip2_q1", type: .multipleChoice, questionText: "Which type of AI tool would be BEST for generating a realistic image from a text description?", options: ["An image generation model like DALL-E or Midjourney", "A text-based chatbot like Claude or ChatGPT", "A spreadsheet formula assistant", "A code completion tool like GitHub Copilot"], correctAnswer: "An image generation model like DALL-E or Midjourney", explanation: "Image generation models are specifically designed to create visuals from text prompts. Text-based chatbots excel at writing and reasoning, not image creation."),
        Question(id: "aip2_q2", type: .trueFalse, questionText: "All AI chatbots are equally good at every task.", options: ["True", "False"], correctAnswer: "False", explanation: "Different AI models have different strengths. Claude is known for careful reasoning, GPT for broad knowledge, and Gemini for multimodal tasks. Choosing the right tool matters."),
        Question(id: "aip2_q3", type: .matchPairs, questionText: "Match each task to the best type of AI tool:", matchPairs: [
            MatchPair(term: "Writing a research summary", definition: "Text-based AI chatbot"),
            MatchPair(term: "Creating a logo concept", definition: "Image generation AI"),
            MatchPair(term: "Transcribing a podcast", definition: "Speech-to-text AI"),
            MatchPair(term: "Translating a document", definition: "Translation AI model")
        ], explanation: "Specialized AI tools often outperform general-purpose ones for specific tasks. Knowing which tool to reach for is a key AI literacy skill."),
        Question(id: "aip2_q4", type: .scenarioJudgment, questionText: "You need to analyze a large spreadsheet of sales data and create charts. Should you use a text-based AI chatbot for this?", options: ["It can help, but a data analysis tool is better", "Yes, chatbots handle data perfectly", "No, AI cannot work with data at all"], correctAnswer: "It can help, but a data analysis tool is better", explanation: "While AI chatbots can discuss data concepts, dedicated data analysis tools or AI features built into spreadsheet apps are better suited for directly manipulating and visualizing large datasets."),
        Question(id: "aip2_q5", type: .fillInBlank, questionText: "When choosing an AI tool, you should consider the task requirements, the tool's __________, and your privacy needs.", options: ["strengths", "popularity", "logo design", "download size"], correctAnswer: "strengths", explanation: "Each AI tool has different strengths and limitations. Matching the tool's capabilities to your specific needs leads to better results."),
        Question(id: "aip2_q6", type: .multipleChoice, questionText: "Why might you choose Claude over another AI model for a sensitive workplace task?", options: ["Claude is designed with a focus on safety and helpfulness", "Claude is the only AI that can access the internet", "Claude is free while all others require payment", "Claude was built before all other AI models"], correctAnswer: "Claude is designed with a focus on safety and helpfulness", explanation: "Anthropic built Claude with a strong emphasis on being helpful, harmless, and honest. Different models have different design philosophies that may suit different use cases.")
    ], order: 1, difficulty: .beginner)

    static let lesson3 = LessonData(id: "aip_l3", title: "Fact-Checking AI", description: "How to verify what AI tells you", categoryId: "ai_practice", questions: [
        Question(id: "aip3_q1", type: .multipleChoice, questionText: "What is the most reliable way to fact-check an AI's response?", options: ["Cross-reference with trusted primary sources", "Ask the same AI if its answer is correct", "Check if the response sounds confident", "Count how many words are in the response"], correctAnswer: "Cross-reference with trusted primary sources", explanation: "The best way to verify AI claims is to check them against authoritative sources like official websites, peer-reviewed research, or established reference materials."),
        Question(id: "aip3_q2", type: .trueFalse, questionText: "If an AI provides a citation or reference, you can always trust that the source exists and says what the AI claims.", options: ["True", "False"], correctAnswer: "False", explanation: "AI models are known to fabricate citations that look real but do not exist. Always verify that cited sources are real and actually support the claims made."),
        Question(id: "aip3_q3", type: .sortOrder, questionText: "Put these fact-checking steps in the best order:", options: ["Search for the claim in trusted sources", "Identify specific claims to verify", "Read the AI response carefully", "Form your final judgment on accuracy"], correctAnswers: ["Read the AI response carefully", "Identify specific claims to verify", "Search for the claim in trusted sources", "Form your final judgment on accuracy"], explanation: "Effective fact-checking follows a structured process: read, identify checkable claims, verify each against reliable sources, then assess overall accuracy."),
        Question(id: "aip3_q4", type: .scenarioJudgment, questionText: "An AI tells you that a specific scientific study found that drinking coffee cures headaches, and provides an author name and journal. What should you do?", options: ["Search for the study to confirm it exists", "Trust it because it cited a journal", "Ignore it because AI is never right"], correctAnswer: "Search for the study to confirm it exists", explanation: "AI models frequently generate plausible-sounding but completely fabricated citations. Always search for the actual study to verify it exists and supports the claim."),
        Question(id: "aip3_q5", type: .fillInBlank, questionText: "AI models tend to hallucinate more when asked about __________ or niche topics with limited training data.", options: ["obscure", "popular", "simple", "mathematical"], correctAnswer: "obscure", explanation: "AI models are more likely to generate incorrect information about obscure topics, recent events, or highly specialized subjects where training data is limited."),
        Question(id: "aip3_q6", type: .multipleChoice, questionText: "Which type of AI claim is MOST likely to be a hallucination?", options: ["A specific statistic with an exact percentage and date", "A general explanation of how photosynthesis works", "A definition of a common English word", "A basic math calculation like 2 + 2"], correctAnswer: "A specific statistic with an exact percentage and date", explanation: "Specific numbers, dates, and statistics are among the most commonly hallucinated details. General knowledge and well-known concepts are more likely to be accurate.")
    ], order: 2, difficulty: .intermediate)

    static let lesson4 = LessonData(id: "aip_l4", title: "AI for School & Work", description: "Using AI ethically in academic and professional settings", categoryId: "ai_practice", questions: [
        Question(id: "aip4_q1", type: .multipleChoice, questionText: "Which of the following is generally considered an ETHICAL use of AI for schoolwork?", options: ["Using AI to help brainstorm ideas before writing your own essay", "Having AI write your entire essay and submitting it as your own", "Using AI to take an exam for you remotely", "Copying AI output verbatim into a research paper"], correctAnswer: "Using AI to help brainstorm ideas before writing your own essay", explanation: "Using AI as a brainstorming tool while doing your own writing is generally acceptable. Submitting AI-generated work as your own is considered academic dishonesty."),
        Question(id: "aip4_q2", type: .trueFalse, questionText: "It is always acceptable to use AI to write professional emails at work without telling anyone.", options: ["True", "False"], correctAnswer: "False", explanation: "Workplace policies on AI use vary widely. Some companies encourage it, others restrict it. Always check your organization's AI policy and be transparent about AI assistance when appropriate."),
        Question(id: "aip4_q3", type: .scenarioJudgment, questionText: "Your teacher says you can use AI tools for a project but must cite any AI assistance. You use Claude to help outline your presentation. What should you do?", options: ["Include a note that AI assisted with the outline", "Say nothing since it was just an outline", "Pretend you did everything yourself"], correctAnswer: "Include a note that AI assisted with the outline", explanation: "When instructed to disclose AI use, honesty is essential. Citing AI assistance, even for outlines or brainstorming, builds trust and follows academic integrity guidelines."),
        Question(id: "aip4_q4", type: .matchPairs, questionText: "Match each AI use case to whether it is generally ethical or not:", matchPairs: [
            MatchPair(term: "Brainstorming ideas with AI", definition: "Generally ethical"),
            MatchPair(term: "Submitting AI text as your own", definition: "Generally unethical"),
            MatchPair(term: "Using AI to check grammar", definition: "Generally ethical"),
            MatchPair(term: "Using AI to fake research data", definition: "Always unethical")
        ], explanation: "The key distinction is whether AI is a tool that assists your own work versus a replacement for your own effort and honesty."),
        Question(id: "aip4_q5", type: .fillInBlank, questionText: "When using AI for work or school, it is important to maintain __________ about how you used the tool.", options: ["transparency", "secrecy", "confusion", "indifference"], correctAnswer: "transparency", explanation: "Being transparent about AI use helps maintain trust, follows policies, and ensures you get credit for your genuine contributions while acknowledging AI assistance."),
        Question(id: "aip4_q6", type: .multipleChoice, questionText: "A colleague asks you to review a report they wrote. You notice it reads like it was entirely generated by AI. What is the best approach?", options: ["Privately suggest they add their own analysis and perspective", "Report them to management immediately", "Say nothing and approve the report", "Rewrite it yourself using a different AI"], correctAnswer: "Privately suggest they add their own analysis and perspective", explanation: "A constructive approach is to privately encourage them to add personal insights and verify the content. This maintains the relationship while promoting responsible AI use.")
    ], order: 3, difficulty: .intermediate)

    static let lesson5 = LessonData(id: "aip_l5", title: "Debugging AI Mistakes", description: "Why AI gets things wrong and how to fix it", categoryId: "ai_practice", questions: [
        Question(id: "aip5_q1", type: .multipleChoice, questionText: "When an AI gives you an incorrect or unhelpful response, what is the BEST first step?", options: ["Rephrase your question with more specific details", "Give up and do the task manually", "Ask the exact same question again", "Switch to a completely different AI model"], correctAnswer: "Rephrase your question with more specific details", explanation: "Rephrasing with more context, constraints, or specific details often dramatically improves AI output. The quality of your prompt directly affects the quality of the response."),
        Question(id: "aip5_q2", type: .trueFalse, questionText: "If an AI misunderstands your question, it is always the AI's fault and never related to how you phrased it.", options: ["True", "False"], correctAnswer: "False", explanation: "Communication with AI is a two-way process. Vague, ambiguous, or poorly structured prompts often lead to poor responses. Improving your prompt is often the fastest fix."),
        Question(id: "aip5_q3", type: .sortOrder, questionText: "Put these debugging steps in the most effective order:", options: ["Add constraints or examples to your prompt", "Identify what went wrong in the response", "Try the improved prompt", "Review the original prompt for ambiguity"], correctAnswers: ["Identify what went wrong in the response", "Review the original prompt for ambiguity", "Add constraints or examples to your prompt", "Try the improved prompt"], explanation: "Effective AI debugging follows a cycle: diagnose the problem, analyze your prompt, refine it with more specificity, and test again."),
        Question(id: "aip5_q4", type: .scenarioJudgment, questionText: "You ask an AI to write a formal business email, but it responds with a casual, friendly tone. What should you try?", options: ["Specify the tone explicitly in your prompt", "Accept the casual tone as good enough", "Conclude that AI cannot write formal emails"], correctAnswer: "Specify the tone explicitly in your prompt", explanation: "Adding explicit instructions about tone, style, and format helps AI models match your expectations. Try: 'Write a formal business email with a professional tone.'"),
        Question(id: "aip5_q5", type: .fillInBlank, questionText: "Providing the AI with a specific __________ of the desired output can help it understand exactly what you want.", options: ["example", "password", "timer", "discount"], correctAnswer: "example", explanation: "Showing the AI an example of what you want (few-shot prompting) is one of the most effective techniques for getting better results from any AI model."),
        Question(id: "aip5_q6", type: .matchPairs, questionText: "Match each AI mistake to its likely cause:", matchPairs: [
            MatchPair(term: "Off-topic response", definition: "Vague or ambiguous prompt"),
            MatchPair(term: "Outdated information", definition: "Training data cutoff"),
            MatchPair(term: "Made-up statistics", definition: "Hallucination tendency"),
            MatchPair(term: "Wrong format", definition: "Missing format instructions")
        ], explanation: "Understanding why AI makes specific types of mistakes helps you craft better prompts and know when to verify outputs more carefully.")
    ], order: 4, difficulty: .advanced)

    static let lesson6 = LessonData(id: "aip_l6", title: "AI Power User", description: "Advanced workflows and techniques", categoryId: "ai_practice", questions: [
        Question(id: "aip6_q1", type: .multipleChoice, questionText: "What is 'prompt chaining'?", options: ["Using the output of one AI prompt as input for the next", "Asking the same question to multiple AI models at once", "Repeating the same prompt until you get a good answer", "Connecting multiple AI accounts together"], correctAnswer: "Using the output of one AI prompt as input for the next", explanation: "Prompt chaining breaks complex tasks into smaller steps, using each AI response to inform the next prompt. This technique produces higher quality results for complex work."),
        Question(id: "aip6_q2", type: .trueFalse, questionText: "Using multiple AI tools together for different parts of a project is a good strategy.", options: ["True", "False"], correctAnswer: "True", explanation: "Combining different AI tools leverages each one's strengths. For example, use Claude for research and writing, DALL-E for images, and a code assistant for programming."),
        Question(id: "aip6_q3", type: .scenarioJudgment, questionText: "You need to create a presentation about renewable energy. Should you use AI for the entire workflow — research, writing, slide design, and image creation?", options: ["Yes, but verify everything and add your own insights", "No, AI should only be used for one task", "Yes, and submit it without any review"], correctAnswer: "Yes, but verify everything and add your own insights", explanation: "AI can assist across an entire workflow, but human oversight, verification, and personal insight are essential at every stage to ensure quality and accuracy."),
        Question(id: "aip6_q4", type: .sortOrder, questionText: "Put these steps of an AI-assisted research workflow in order:", options: ["Write the final draft with your own analysis", "Use AI to summarize key findings", "Define your research question clearly", "Verify AI summaries against original sources"], correctAnswers: ["Define your research question clearly", "Use AI to summarize key findings", "Verify AI summaries against original sources", "Write the final draft with your own analysis"], explanation: "An effective AI-assisted workflow starts with clear goals, uses AI for heavy lifting, verifies the output, and finishes with your own critical thinking and writing."),
        Question(id: "aip6_q5", type: .fillInBlank, questionText: "A __________ prompt includes context, instructions, examples, and constraints to get the best AI output.", options: ["structured", "random", "shortest", "encrypted"], correctAnswer: "structured", explanation: "Structured prompts that include clear context, specific instructions, relevant examples, and explicit constraints consistently produce better results from AI models."),
        Question(id: "aip6_q6", type: .multipleChoice, questionText: "What is a key advantage of using AI to iterate on your work?", options: ["You can quickly explore multiple approaches and variations", "AI eliminates the need for any human review", "AI-generated iterations are always improvements", "It guarantees your work will be perfect on the first try"], correctAnswer: "You can quickly explore multiple approaches and variations", explanation: "AI excels at rapidly generating variations and alternatives, helping you explore different angles, tones, and approaches much faster than working alone.")
    ], order: 5, difficulty: .advanced)
}
